import os
import shutil

def reorganize_files(directory, archive_directory):
    # Check if the archive directory exists, and create it if it doesn't
    if not os.path.exists(archive_directory):
        os.makedirs(archive_directory)

    # Iterate over all files and directories in the given directory
    for root, dirs, files in os.walk(directory):
        # Ignore directories with special characters in their names
        if any(not c.isalnum() for c in os.path.basename(root)):
            continue

        # Move each file to the archive directory
        for file in files:
            if not file.isalnum():
                continue
            shutil.move(os.path.join(root, file), archive_directory)

# Usage
reorganize_files('/path/to/your/directory', '/path/to/archive/directory')
